// Extract AI-generated content and format for Next.js markdown blog
const items = $input.all();
const processedItems = [];

for (const item of items) {
  const aiOutput = item.json.output || item.json.text || '';

  // Extract title (first line or marked with Title:)
  let title = '';
  let content = aiOutput;

  // Try to extract title from various formats
  const titleMatch = aiOutput.match(/^(?:Title:|#)\s*(.+?)(?:\n|$)/i);
  if (titleMatch) {
    title = titleMatch[1].trim();
    content = aiOutput.replace(/^(?:Title:|#)\s*.+?(?:\n|$)/i, '').trim();
  } else {
    // Use first line as title if no marker
    const lines = aiOutput.split('\n');
    title = lines[0].trim().replace(/^#+\s*/, '');
    content = lines.slice(1).join('\n').trim();
  }

  // Clean the title
  const cleanTitle = title.replace(/[^a-zA-Z0-9\s-]/g, '').replace(/\s+/g, ' ').trim();

  // Generate slug from title (for filename)
  const slug = cleanTitle
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');

  // Get current date in YYYY-MM-DD format
  const today = new Date();
  const dateStr = today.toISOString().split('T')[0];

  // Ensure content is proper markdown (clean up any HTML)
  let markdownContent = content
    .replace(/<p>/g, '')
    .replace(/<\/p>/g, '\n\n')
    .replace(/<strong>(.+?)<\/strong>/g, '**$1**')
    .replace(/<em>(.+?)<\/em>/g, '*$1*')
    .replace(/<h2>(.+?)<\/h2>/g, '## $1')
    .replace(/<h3>(.+?)<\/h3>/g, '### $1')
    .replace(/<ul>/g, '')
    .replace(/<\/ul>/g, '\n')
    .replace(/<li>(.+?)<\/li>/g, '- $1\n')
    .replace(/<a href="(.+?)">(.+?)<\/a>/g, '[$2]($1)')
    .trim();

  // Create frontmatter (image will be added later)
  const frontmatter = `---\ntitle: "${cleanTitle}"\ndate: "${dateStr}"\nslug: "${slug}"\ncategory: "Industry Updates"\n---\n\n`;

  // Combine frontmatter and content
  const fullMarkdown = frontmatter + markdownContent;

  // Base64 encode for GitHub API
  const base64Content = Buffer.from(fullMarkdown, 'utf8').toString('base64');

  processedItems.push({
    json: {
      ...item.json,
      title: cleanTitle,
      slug: slug,
      date: dateStr,
      filename: `${slug}.md`,
      content: markdownContent,
      fullMarkdown: fullMarkdown,
      base64Content: base64Content,
      filePath: `content/blog/${slug}.md`
    }
  });
}

return processedItems;

// Generate image prompt from blog post title
const items = $input.all();
const processedItems = [];

for (const item of items) {
  const title = item.json.title || '';
  const content = item.json.content || '';

  // Extract key themes from content (first 200 chars)
  const contentPreview = content.substring(0, 200).toLowerCase();

  // Create a descriptive image prompt
  let imagePrompt = `A professional, modern illustration representing: ${title}. `;

  // Add context based on common industry/tech themes
  if (contentPreview.includes('startup') || contentPreview.includes('business')) {
    imagePrompt += 'Style: business and innovation, with startup and entrepreneurship visual elements. ';
  }
  if (contentPreview.includes('enterprise') || contentPreview.includes('corporate')) {
    imagePrompt += 'Include enterprise and corporate technology themes. ';
  }
  if (contentPreview.includes('innovation') || contentPreview.includes('technology')) {
    imagePrompt += 'Technology innovation and digital transformation themes. ';
  }
  if (contentPreview.includes('market') || contentPreview.includes('trend')) {
    imagePrompt += 'Industry trends and market analysis visual elements. ';
  }

  imagePrompt += 'Color scheme: professional business colors (blues, grays, modern gradients). Clean, corporate design suitable for a blog header image. 16:9 aspect ratio, high quality.';

  processedItems.push({
    json: {
      ...item.json,
      imagePrompt: imagePrompt,
      imageFilename: `${item.json.slug}-header.jpg`
    }
  });
}

return processedItems;

