// Extract base64 image data from OpenRouter response
const items = $input.all();
const processedItems = [];

for (const item of items) {
  try {
    const response = item.json;

    // Extract image from response
    let base64Image = '';

    if (response.choices && 
        response.choices[0] && 
        response.choices[0].message && 
        response.choices[0].message.images && 
        response.choices[0].message.images[0] && 
        response.choices[0].message.images[0].image_url && 
        response.choices[0].message.images[0].image_url.url) {

      const imageUrl = response.choices[0].message.images[0].image_url.url;

      // Remove data:image/...;base64, prefix
      base64Image = imageUrl.replace(/^data:image\/[^;]+;base64,/, '');
    } else {
      throw new Error('Image not found in response. Response structure: ' + JSON.stringify(response, null, 2));
    }

    // Get image filename from previous node
    const imagePromptNode = $('Generate Image Prompt').first();
    const imageFilename = imagePromptNode ? imagePromptNode.json.imageFilename : 'image.jpg';

    processedItems.push({
      json: {
        ...item.json,
        base64Image: base64Image,
        imageFilename: imageFilename
      }
    });
  } catch (error) {
    // Pass through error for debugging
    processedItems.push({
      json: {
        ...item.json,
        error: error.message,
        base64Image: ''
      }
    });
  }
}

return processedItems;

// Update markdown frontmatter with image URL
const items = $input.all();
const processedItems = [];

for (const item of items) {
  const title = item.json.title;
  const slug = item.json.slug;
  const date = item.json.date;
  const content = item.json.content;
  const imageFilename = item.json.imageFilename;

  // Create image URL (assuming your site is hosted and images are accessible)
  // Update this URL to match your actual domain
  const imageUrl = `/images/blog/${imageFilename}`;

  // Create frontmatter with image
  const frontmatter = `---\ntitle: "${title}"\ndate: "${date}"\nslug: "${slug}"\nimage: "${imageUrl}"\ncategory: "Industry Updates"\n---\n\n`;

  // Combine frontmatter and content
  const fullMarkdown = frontmatter + content;

  // Base64 encode for GitHub API
  const base64Content = Buffer.from(fullMarkdown, 'utf8').toString('base64');

  processedItems.push({
    json: {
      title: title,
      slug: slug,
      date: date,
      filename: `${slug}.md`,
      content: content,
      imageUrl: imageUrl,
      imageFilename: imageFilename,
      fullMarkdown: fullMarkdown,
      base64Content: base64Content,
      filePath: `content/blog/${slug}.md`
    }
  });
}

return processedItems;
